/**
 * @param {number[]} nums
 * @param {number} k
 * @return {number}
 */
function solve(nums, k) {
    const n = nums.length;
    if (n === 0) {
        return 0;
    }

    // dp[i][0]: maximum score of a valid subsequence ending at index i,
    // where nums[i] is the smaller element in the last comparison (i.e., prev < nums[i] > next or prev > nums[i] < next)
    // More precisely:
    // dp[i][0]: max score ending at i, where the sequence ends with ... < nums[i] (i.e., it's a valley or the first element)
    // dp[i][1]: max score ending at i, where the sequence ends with ... > nums[i] (i.e., it's a peak)

    // Let's refine the state based on the required alternating pattern:
    // State 0: The sequence ending at i must have the property: nums[i] < nums[prev] (i.e., it's a "valley" relative to the previous element)
    // State 1: The sequence ending at i must have the property: nums[i] > nums[prev] (i.e., it's a "peak" relative to the previous element)

    // Base case: A sequence of length 1 has no previous element, so it can be considered both a peak and a valley starter.
    // We initialize all scores to nums[i] because any single element is a valid sequence.

    // dp[i][0]: Max score ending at i, where the last transition was an ascent (nums[prev] < nums[i]).
    // dp[i][1]: Max score ending at i, where the last transition was a descent (nums[prev] > nums[i]).

    // A length 1 sequence is both a peak and a valley.
    // Let's use:
    // dp[i][0]: Max score of a valid alternating sequence ending at i, where the required *next* comparison is '>' (i.e., it ended with an ascent: ... < nums[i]).
    // dp[i][1]: Max score of a valid alternating sequence ending at i, where the required *next* comparison is '<' (i.e., it ended with a descent: ... > nums[i]).

    const dp = Array(n).fill(0).map(() => [nums[0], nums[0]]); // Initialize with nums[0] for index 0

    for (let i = 0; i < n; i++) {
        // Base case: A sequence of length 1
        dp[i][0] = nums[i]; // Can start with an ascent expectation (or just be length 1)
        dp[i][1] = nums[i]; // Can start with a descent expectation (or just be length 1)

        for (let j = 0; j < i; j++) {
            if (i - j >= k) {
                // Case 1: Transition from j to i is an ascent (nums[j] < nums[i]).
                // If we extend a sequence ending at j:
                // 1. If sequence at j ended with descent (... > nums[j]), we can extend it with ascent: ... > nums[j] < nums[i].
                //    The new state at i must expect a descent (dp[i][1]).
                if (nums[j] < nums[i]) {
                    // Extend sequence ending in descent at j (dp[j][1])
                    dp[i][1] = Math.max(dp[i][1], dp[j][1] + nums[i]);

                    // Also, a sequence of length 1 at j, which is implicitly covered by the base case,
                    // can transition here. However, we must ensure the structure is maintained.
                    // If dp[j][0] is used, it means sequence at j ended with ascent, so next must be descent.
                    // This path (ascend -> ascend) is invalid.
                }

                // Case 2: Transition from j to i is a descent (nums[j] > nums[i]).
                // If we extend a sequence ending at j:
                // 1. If sequence at j ended with ascent (... < nums[j]), we can extend it with descent: ... < nums[j] > nums[i].
                //    The new state at i must expect an ascent (dp[i][0]).
                if (nums[j] > nums[i]) {
                    // Extend sequence ending in ascent at j (dp[j][0])
                    dp[i][0] = Math.max(dp[i][0], dp[j][0] + nums[i]);
                }
            }
        }
    }

    let maxScore = 0;
    for (let i = 0; i < n; i++) {
        maxScore = Math.max(maxScore, dp[i][0], dp[i][1]);
    }

    return maxScore;
}

